-- Program: Office Worker Recovery
-- Category: Flexibility/Stretches -> flexibility
-- Priority: High
-- Durations: [1, 2, 4], Sessions: [5, 5, 7]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Office Worker Recovery',
    'Short daily stretching routines designed to counteract the effects of prolonged sitting. Targets neck, shoulders, chest, hip flexors, and lower back with desk-job-specific relief.',
    'flexibility',
    'all_levels',
    4,
    7,
    'flow',
    ARRAY['Improve flexibility', 'Enhance body awareness', 'Promote active recovery', 'Reduce injury risk']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

